const response = $input.first().json;

// Default values
let idea = 'Embrace every challenge as a stepping stone to greatness';
let imagePrompt = 'person standing on mountain peak golden hour cinematic ultra HD vibrant colors';
let caption = '🔥 Every obstacle is a stepping stone!\n\n💪 Believe in yourself.\n🌟 Your future self will thank you!\n\n#Motivation #Success #Mindset #Growth #Hustle #Inspire #Believe #Achieve #DailyMotivation #Winning';

try {
  // Groq response parse করো
  const content = response.choices[0].message.content;
  console.log('Raw LLM response:', content.substring(0, 200));

  // JSON extract করো
  const clean = content
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  const jsonMatch = clean.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    idea = parsed.idea || idea;
    imagePrompt = parsed.imagePrompt || imagePrompt;
    caption = parsed.caption || caption;
    console.log('✅ Parsed successfully');
    console.log('Idea:', idea.substring(0, 60));
    console.log('Caption preview:', caption.substring(0, 80));
  }
} catch(e) {
  console.log('Parse error, using defaults:', e.message);
}

// Random image
const seed = Math.floor(Math.random() * 999999);
const imageUrl = `https://picsum.photos/1080/1080?random=${seed}`;

// Caption clean করো - newlines রাখো
const cleanCaption = caption
  .replace(/\\n/g, '\n')
  .trim();

return [{ 
  json: { 
    idea,
    imagePrompt,
    caption: cleanCaption,
    imageUrl,
    date: new Date().toISOString(),
    seed
  } 
}];

const fbResult = $input.first().json;
const content = $('⚙️ Parse & Build Content').first().json;

const success = !!fbResult.post_id || !!fbResult.id;
const postId = fbResult.post_id || fbResult.id || 'N/A';

if (success) {
  console.log('🎉 SUCCESS! Facebook Post ID:', postId);
  console.log('📅 Date:', content.date);
  console.log('💡 Idea:', content.idea);
} else {
  console.log('❌ FAILED:', JSON.stringify(fbResult.error || fbResult));
}

return [{ json: { success, postId, ...content, fbResponse: fbResult } }];
